19: void ActiveStreamListenerBase::emitLogs(Network::ListenerConfig& config,
20:                                         StreamInfo::StreamInfo& stream_info) {
21:   stream_info.onRequestComplete();
22:   for (const auto& access_log : config.accessLogs()) {
23:     access_log->log({}, stream_info);
24:   }
25: }
