85:   connection_->noDelay(true);
86:   auto& listener = active_connections_.listener_;
87:   listener.stats_.downstream_cx_total_.inc();
88:   listener.stats_.downstream_cx_active_.inc();
89:   listener.per_worker_stats_.downstream_cx_total_.inc();
90:   listener.per_worker_stats_.downstream_cx_active_.inc();
91: 
92:   // Active connections on the handler (not listener). The per listener connections have already
93:   // been incremented at this point either via the connection balancer or in the socket accept
94:   // path if there is no configured balancer.
95:   listener.parent_.incNumConnections();
96: }
