543: FilterChainManagerImpl::findFilterChain(const Network::ConnectionSocket& socket,
544:                                         const StreamInfo::StreamInfo& info) const {
545:   if (matcher_) {
546:     return findFilterChainUsingMatcher(socket, info);
547:   }
548: 
549:   const auto& address = socket.connectionInfoProvider().localAddress();
550: 
551:   const Network::FilterChain* best_match_filter_chain = nullptr;
552:   // Match on destination port (only for IP addresses).
553:   if (address->type() == Network::Address::Type::Ip) {
554:     const auto port_match = destination_ports_map_.find(address->ip()->port());
555:     if (port_match != destination_ports_map_.end()) {
556:       best_match_filter_chain = findFilterChainForDestinationIP(*port_match->second.second, socket);
557:       if (best_match_filter_chain != nullptr) {
558:         return best_match_filter_chain;
559:       } else {
560:         // There is entry for specific port but none of the filter chain matches. Instead of
561:         // matching catch-all port 0, the fallback filter chain is returned.
562:         return default_filter_chain_.get();
563:       }
564:     }
565:   }
566:   // Match on catch-all port 0 if there is no specific port sub tree.
567:   const auto port_match = destination_ports_map_.find(0);
568:   if (port_match != destination_ports_map_.end()) {
569:     best_match_filter_chain = findFilterChainForDestinationIP(*port_match->second.second, socket);
570:   }
571:   return best_match_filter_chain != nullptr
572:              ? best_match_filter_chain
573:              // Neither exact port nor catch-all port matches. Use fallback filter chain.
574:              : default_filter_chain_.get();
575: }
