578: FilterChainManagerImpl::findFilterChainUsingMatcher(const Network::ConnectionSocket& socket,
579:                                                     const StreamInfo::StreamInfo& info) const {
580:   Network::Matching::MatchingDataImpl data(socket, info.filterState(), info.dynamicMetadata());
581:   const Matcher::MatchResult match_result =
582:       Matcher::evaluateMatch<Network::MatchingData>(*matcher_, data);
583:   ASSERT(match_result.isComplete(), "Matching must complete for network streams.");
584:   if (match_result.isMatch()) {
585:     return match_result.action()->getTyped<Configuration::FilterChainBaseAction>().get(
586:         filter_chains_by_name_, info);
587:   }
588:   return default_filter_chain_.get();
589: }
