591: const Network::FilterChain* FilterChainManagerImpl::findFilterChainForDestinationIP(
592:     const DestinationIPsTrie& destination_ips_trie, const Network::ConnectionSocket& socket) const {
593:   auto address = socket.connectionInfoProvider().localAddress();
594:   if (address->type() != Network::Address::Type::Ip) {
595:     address = FilterChain::fakeAddress();
596:   }
597: 
598:   // Match on both: exact IP and wider CIDR ranges using LcTrie.
599:   const auto& data = destination_ips_trie.getData(address);
600:   if (!data.empty()) {
601:     ASSERT(data.size() == 1);
602:     return findFilterChainForServerName(*data.back(), socket);
603:   }
604: 
605:   return nullptr;
606: }
