608: const Network::FilterChain* FilterChainManagerImpl::findFilterChainForServerName(
609:     const ServerNamesMap& server_names_map, const Network::ConnectionSocket& socket) const {
610:   ASSERT(absl::AsciiStrToLower(socket.requestedServerName()) == socket.requestedServerName());
611:   const std::string server_name(socket.requestedServerName());
612: 
613:   // Match on exact server name, i.e. "www.example.com" for "www.example.com".
614:   const auto server_name_exact_match = server_names_map.find(server_name);
615:   if (server_name_exact_match != server_names_map.end()) {
616:     return findFilterChainForTransportProtocol(server_name_exact_match->second, socket);
617:   }
618: 
619:   // Match on all wildcard domains, i.e. ".example.com" and ".com" for "www.example.com".
620:   size_t pos = server_name.find('.', 1);
621:   while (pos < server_name.size() - 1 && pos != std::string::npos) {
622:     const std::string wildcard = server_name.substr(pos);
623:     const auto server_name_wildcard_match = server_names_map.find(wildcard);
624:     if (server_name_wildcard_match != server_names_map.end()) {
625:       return findFilterChainForTransportProtocol(server_name_wildcard_match->second, socket);
626:     }
627:     pos = server_name.find('.', pos + 1);
628:   }
629: 
630:   // Match on a filter chain without server name requirements.
631:   const auto server_name_catchall_match = server_names_map.find(EMPTY_STRING);
632:   if (server_name_catchall_match != server_names_map.end()) {
633:     return findFilterChainForTransportProtocol(server_name_catchall_match->second, socket);
634:   }
635: 
636:   return nullptr;
637: }
