574: void FilterManager::decodeHeaders(ActiveStreamDecoderFilter* filter, RequestHeaderMap& headers,
575:                                   bool end_stream) {
576:   // Headers filter iteration should always start with the next filter if available.
577:   StreamDecoderFilters::Iterator entry =
578:       commonDecodePrefix(filter, FilterIterationStartState::AlwaysStartFromNext);
579:   StreamDecoderFilters::Iterator continue_data_entry = decoder_filters_.end();
580:   bool terminal_filter_decoded_end_stream = false;
581:   ASSERT(!state_.decoder_filter_chain_complete_ || entry == decoder_filters_.end() ||
582:          (*entry)->end_stream_);
583: 
584:   for (; entry != decoder_filters_.end(); entry++) {
585:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
586:     ASSERT(!(state_.filter_call_state_ & FilterCallState::DecodeHeaders));
587:     state_.filter_call_state_ |= FilterCallState::DecodeHeaders;
588:     (*entry)->end_stream_ = (end_stream && continue_data_entry == decoder_filters_.end());
589:     if ((*entry)->end_stream_) {
590:       state_.filter_call_state_ |= FilterCallState::EndOfStream;
591:     }
592:     FilterHeadersStatus status = (*entry)->decodeHeaders(headers, (*entry)->end_stream_);
593:     state_.filter_call_state_ &= ~FilterCallState::DecodeHeaders;
594:     if ((*entry)->end_stream_) {
595:       state_.filter_call_state_ &= ~FilterCallState::EndOfStream;
596:     }
597:     if (state_.decoder_filter_chain_aborted_) {
598:       executeLocalReplyIfPrepared();
599:       ENVOY_STREAM_LOG(trace,
600:                        "decodeHeaders filter iteration aborted due to local reply: filter={}",
601:                        *this, (*entry)->filter_context_.config_name);
602:       status = FilterHeadersStatus::StopIteration;
603:     }
604: 
605:     ASSERT(!(status == FilterHeadersStatus::ContinueAndDontEndStream && !(*entry)->end_stream_),
606:            "Filters should not return FilterHeadersStatus::ContinueAndDontEndStream from "
607:            "decodeHeaders when end_stream is already false");
608: 
609:     ENVOY_STREAM_LOG(trace, "decode headers called: filter={} status={}", *this,
610:                      (*entry)->filter_context_.config_name, static_cast<uint64_t>(status));
611: 
612:     (*entry)->processed_headers_ = true;
613: 
614:     const auto continue_iteration = (*entry)->commonHandleAfterHeadersCallback(status, end_stream);
615:     ENVOY_BUG(!continue_iteration || !stopDecoderFilterChain(),
616:               fmt::format(
617:                   "filter={} did not return StopAll or StopIteration after sending a local reply.",
618:                   (*entry)->filter_context_.config_name));
619: 
620:     // If this filter ended the stream, decodeComplete() should be called for it.
621:     if ((*entry)->end_stream_) {
622:       (*entry)->handle_->decodeComplete();
623:     }
624: 
625:     // Skip processing metadata after sending local reply
626:     if (stopDecoderFilterChain() && std::next(entry) != decoder_filters_.end()) {
627:       maybeContinueDecoding(continue_data_entry);
628:       return;
629:     }
630: 
631:     const bool new_metadata_added = processNewlyAddedMetadata();
632:     // If end_stream is set in headers, and a filter adds new metadata, we need to delay end_stream
633:     // in headers by inserting an empty data frame with end_stream set. The empty data frame is sent
634:     // after the new metadata.
635:     if ((*entry)->end_stream_ && new_metadata_added && !buffered_request_data_) {
636:       Buffer::OwnedImpl empty_data("");
637:       ENVOY_STREAM_LOG(
638:           trace, "inserting an empty data frame for end_stream due metadata being added.", *this);
639:       // Metadata frame doesn't carry end of stream bit. We need an empty data frame to end the
640:       // stream.
641:       addDecodedData(*(*entry), empty_data, true);
642:     }
643: 
644:     if (!continue_iteration && std::next(entry) != decoder_filters_.end()) {
645:       // Stop iteration IFF this is not the last filter. If it is the last filter, continue with
646:       // processing since we need to handle the case where a terminal filter wants to buffer, but
647:       // a previous filter has added body.
648:       maybeContinueDecoding(continue_data_entry);
649:       return;
650:     }
651: 
652:     // Here we handle the case where we have a header only request, but a filter adds a body
653:     // to it. We need to not raise end_stream = true to further filters during inline iteration.
654:     if (end_stream && buffered_request_data_ && continue_data_entry == decoder_filters_.end()) {
655:       continue_data_entry = entry;
656:     }
657:     // The decoder filter chain is finished here if the following is true:
658:     // 1. the last filter has observed the end_stream AND
659:     // 2. no filter, including the last filter, has injected body during header iteration.
660:     // If body was injected the end_stream will be processed in the `decodeData()` method below.
661:     const bool no_body_was_injected = continue_data_entry == decoder_filters_.end();
662:     terminal_filter_decoded_end_stream =
663:         (std::next(entry) == decoder_filters_.end() && (*entry)->end_stream_) &&
664:         no_body_was_injected;
665:   }
666: 
667:   maybeContinueDecoding(continue_data_entry);
668: 
669:   if (end_stream) {
670:     disarmRequestTimeout();
671:   }
672:   maybeEndDecode(terminal_filter_decoded_end_stream);
673: }
