299:     const envoy::extensions::filters::network::http_connection_manager::v3::HttpConnectionManager&
300:         proto_config,
301:     Server::Configuration::FactoryContext& context, bool clear_hop_by_hop_headers) {
302:   Utility::Singletons singletons = Utility::createSingletons(context);
