304:   auto config_or_error = Utility::createConfig(
305:       proto_config, context, *singletons.date_provider_, *singletons.route_config_provider_manager_,
306:       singletons.scoped_routes_config_provider_manager_.get(), *singletons.tracer_manager_,
307:       *singletons.filter_config_provider_manager_);
308:   RETURN_IF_NOT_OK_REF(config_or_error.status());
309:   auto filter_config = std::move(*config_or_error);
310: 
311:   // This lambda captures the shared_ptrs created above, thus preserving the
312:   // reference count.
313:   // Keep in mind the lambda capture list **doesn't** determine the destruction order, but it's fine
314:   // as these captured objects are also global singletons.
315:   return [singletons, filter_config, &context,
316:           clear_hop_by_hop_headers](Network::FilterManager& filter_manager) -> void {
317:     auto& server_context = context.serverFactoryContext();
318:     Server::OverloadManager& overload_manager = context.listenerInfo().shouldBypassOverloadManager()
319:                                                     ? server_context.nullOverloadManager()
320:                                                     : server_context.overloadManager();
321:     auto hcm = std::make_shared<Http::ConnectionManagerImpl>(
322:         filter_config, context.drainDecision(), server_context.api().randomGenerator(),
323:         server_context.httpContext(), server_context.runtime(), server_context.localInfo(),
324:         server_context.clusterManager(), overload_manager,
325:         server_context.mainThreadDispatcher().timeSource(), context.listenerInfo().direction());
326:     if (!clear_hop_by_hop_headers) {
327:       hcm->setClearHopByHopResponseHeaders(false);
328:     }
329:     filter_manager.addReadFilter(std::move(hcm));
330:   };
