1261:                                   bool end_stream) {
1262:   // See encodeHeaders() comments in envoy/http/filter.h for why the 1xx precondition holds.
1263:   ASSERT(!CodeUtility::is1xx(Utility::getResponseStatus(headers)) ||
1264:          Utility::getResponseStatus(headers) == enumToInt(Http::Code::SwitchingProtocols));
