1718:       response_code_for_outlier_detection = grpc_to_http_status;
1719:     }
1720:   } else {
1721:     // Check cluster's http_protocol_options if different code should be reported to
1722:     // outlier detector.
1723:     absl::optional<bool> matched = cluster_->processHttpForOutlierDetection(*headers);
1724:     if (matched.has_value()) {
1725:       // Outlier detector distinguishes only two values:
1726:       // Anything >= 500 is error.
1727:       // Anything < 500 is success.
1728:       if (!matched.value()) {
1729:         // Matcher returned non-match.
1730:         // report success to outlier detector.
1731:         response_code_for_outlier_detection = 200;
1732:       } else {
1733:         // Matcher returned match (treat the response as error).
1734:         // If the original status code was error (>= 500), then report the
1735:         // original status code to the outlier detector.
1736:         if (response_code < 500) {
1737:           response_code_for_outlier_detection = 500;
1738:         }
1739:       }
1740:     }
1741:   }
1742: 
1743:   upstream_request.upstreamHost()->outlierDetector().putResult(
1744:       response_code_for_outlier_detection >= 500
